    # Make a copy to avoid modifying the original graph
    graph_copy = graph_data.copy()

    # Helper: find node with given name and containing the specified type in its type list
    def find_node(name, type_str):
        for n, data in graph_copy.nodes(data=True):
            if data.get('name') == name and isinstance(data.get('type'), list) and type_str in data['type']:
                return n
        return None

    # Helper: compute total physical capacity (sum of physical_capacity_bps) of all PORT descendants
    def total_port_capacity(start_node):
        total = 0
        # Stack for DFS
        stack = [start_node]
        visited = set()
        while stack:
            node = stack.pop()
            if node in visited:
                continue
            visited.add(node)
            node_data = graph_copy.nodes[node]
            # If this node is a PORT, add its capacity
            if isinstance(node_data.get('type'), list) and 'EK_PORT' in node_data['type']:
                total += node_data.get('physical_capacity_bps', 0)
            # Follow containment edges to children
            for _, tgt, edata in graph_copy.out_edges(node, data=True):
                if edata.get('type') == 'RK_CONTAINS':
                    stack.append(tgt)
        return total

    # Locate the EK_CONTROL_DOMAIN node
    ctrl_node = find_node('ju1.a2.dom', 'EK_CONTROL_DOMAIN')
    if ctrl_node is None:
        result = []
    else:
        # Gather child nodes via RK_CONTAINS edges
        child_info = []
        for _, tgt, edata in graph_copy.out_edges(ctrl_node, data=True):
            if edata.get('type') == 'RK_CONTAINS':
                cap = total_port_capacity(tgt)
                child_name = graph_copy.nodes[tgt].get('name')
                child_info.append((child_name, cap))
        # Sort by capacity descending
        child_info.sort(key=lambda x: x[1], reverse=True)
        result = child_info

    # Prepare output
    output = {
        'type': 'list',
        'data': result,          # list of tuples (will be serialized as list of lists)
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return output

