def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Add the new PORT node
    new_node_attrs = {
        'name': 'new_EK_PORT_43',
        'type': ['EK_PORT'],
        'physical_capacity_bps': 0
    }
    graph_copy.add_node('new_EK_PORT_43', **new_node_attrs)

    # Connect it to the parent via RK_CONTAINS
    parent = 'ju1.a2.dom'
    if parent in graph_copy:
        graph_copy.add_edge(parent, 'new_EK_PORT_43', type='RK_CONTAINS')

    # Gather direct children of the parent
    children = []
    if parent in graph_copy:
        for _, child, edata in graph_copy.out_edges(parent, data=True):
            if edata.get('type') == 'RK_CONTAINS':
                children.append(child)

    # Helper to sum physical_capacity_bps of all PORT descendants
    def total_capacity(node):
        total = 0
        visited = set()
        stack = [node]
        while stack:
            cur = stack.pop()
            if cur in visited:
                continue
            visited.add(cur)
            if 'EK_PORT' in graph_copy.nodes[cur].get('type', []):
                total += graph_copy.nodes[cur].get('physical_capacity_bps', 0)
            for _, nbr, edata in graph_copy.out_edges(cur, data=True):
                if edata.get('type') == 'RK_CONTAINS':
                    stack.append(nbr)
        return total

    # Compute capacities for each child and sort
    child_capacities = [(child, total_capacity(child)) for child in children]
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    # Build result
    result = {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return result

